import {{ Injectable }} from '@nestjs/common';
import {{ DownloadService }} from './models/download.model';
import {{ DownloadServiceRepository }} from './repositories/download.repository';

@Injectable()
export class DownloadServiceService {{
  constructor(
    private readonly repository: DownloadServiceRepository,
  ) {{}}

  async findAll(): Promise<DownloadService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<DownloadService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<DownloadService>): Promise<DownloadService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<DownloadService>): Promise<DownloadService> {{
    return this.repository.update(id, data);
  }}
}}
